import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void banana() {
        assertEquals("ban", new Solution().removeDuplicates("banana"));
    }

    @Test
    void repeatingPairs() {
        // each char appears exactly twice, keep first of each
        assertEquals("abc", new Solution().removeDuplicates("aabbcc"));
    }

    @Test
    void alreadyUnique() {
        assertEquals("abc", new Solution().removeDuplicates("abc"));
    }

    @Test
    void palindromeLike() {
        // "abba" — first occurrence of 'a' is index 0, 'b' is index 1
        assertEquals("ab", new Solution().removeDuplicates("abba"));
    }

    @Test
    void allSame() {
        assertEquals("a", new Solution().removeDuplicates("aaaa"));
    }

    @Test
    void single() {
        assertEquals("z", new Solution().removeDuplicates("z"));
    }

    @Test
    void empty() {
        assertEquals("", new Solution().removeDuplicates(""));
    }
}
